import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";
import { collegeData } from '../data/collegeData'; 

// 🔑 Your API Key
const API_KEY = "AIzaSyBA3WcmWZskhy8Wxqkz6aXTkmmgLbNLe38"; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "👋 Hi! I'm CampusBot. I can help you navigate CampusCanvas or answer questions about NIMIT!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) {
       messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isThinking, isOpen]);

  // --- AI LOGIC ---
  const generateResponse = async (userQuestion) => {
    try {
      if (!API_KEY) return "⚠️ Error: API Key Missing.";
      
      const genAI = new GoogleGenerativeAI(API_KEY);
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash-latest" });

      const systemContext = `
        You are "CampusBot", the official AI assistant for ${collegeData.collegeInfo.name}.
        
        NIMIT KNOWLEDGE BASE:
        - Departments: ${collegeData.collegeInfo.departments.join(", ")}
        - Placements: ${collegeData.collegeInfo.placements.highlights}
        - Campus Events: ${collegeData.collegeInfo.campusLife.majorEvents.join(", ")}
        
        CAMPUSCANVAS APP MANUAL & HELP DESK:
        - Purpose: ${collegeData.appManual.purpose}
        - Developers: ${collegeData.appManual.team}
        - How to Add a Project: ${collegeData.appManual.userGuide.howToAddProject}
        - How to Search: ${collegeData.appManual.userGuide.howToFindProjects}
        - Admin Duties: ${collegeData.appManual.userGuide.adminControls}
        
        BUTTON EXPLANATIONS:
        - '+' Button: ${collegeData.appManual.uiGuide.plusButton}
        - Profile Icon: ${collegeData.appManual.uiGuide.profileIcon}
        - Launch App Button: ${collegeData.appManual.uiGuide.launchAppButton}
        
        INSTRUCTIONS:
        - If a user asks "How do I upload?", give them step-by-step instructions.
        - Keep answers short, friendly, and strictly helpful.
      `;

      const result = await model.generateContent(`${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`);
      const response = await result.response;
      return response.text();
      
    } catch (error) {
      console.error("Debug AI Error:", error);
      // 👇 THIS IS THE CRITICAL DEBUG LINE
      return `⚠️ Debug Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;
    
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);
    
    const aiText = await generateResponse(input);
    
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end font-sans">
      
      {!isOpen && (
        <div className="bg-white text-indigo-900 text-xs font-bold px-3 py-1.5 rounded-lg shadow-md mb-2 mr-2 animate-bounce border border-indigo-100">
          💡 Need Help?
          <div className="absolute right-4 -bottom-1 w-2 h-2 bg-white transform rotate-45 border-r border-b border-indigo-100"></div>
        </div>
      )}

      {isOpen && (
        <div className="bg-white w-80 h-96 rounded-2xl shadow-2xl border border-gray-200 flex flex-col overflow-hidden animate-fade-in-up mb-4">
          <div className="bg-indigo-600 p-4 flex justify-between items-center text-white shadow-md">
            <div className="flex items-center gap-2">
              <span className="text-xl">🤖</span>
              <div><h3 className="font-bold text-sm">CampusBot</h3></div>
            </div>
            <button onClick={onClose} className="hover:bg-indigo-700 w-8 h-8 rounded-full">✕</button>
          </div>

          <div className="flex-1 p-4 overflow-y-auto bg-gray-50 space-y-3">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 rounded-xl text-sm shadow-sm ${msg.isBot ? 'bg-white border border-gray-200 text-gray-800' : 'bg-indigo-600 text-white'}`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isThinking && <div className="text-xs text-gray-400 p-2">Thinking...</div>}
            <div ref={messagesEndRef} />
          </div>

          <div className="p-3 border-t bg-white flex gap-2">
            <input 
              type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." className="flex-1 bg-gray-100 rounded-full px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
            />
            <button onClick={handleSend} disabled={isThinking} className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center">➤</button>
          </div>
        </div>
      )}

      {!isOpen && (
        <button onClick={onOpen} className="w-16 h-16 bg-gradient-to-tr from-indigo-600 to-purple-600 text-white rounded-full shadow-lg flex items-center justify-center text-3xl transition-transform hover:scale-110 active:scale-95 border-2 border-white/20">
          🤖
        </button>
      )}
    </div>
  );
}

export default ChatBot;
